import { useState } from "react";
import "./index.css";

const initialTasks = [
  { id: 1, name: "Оновити ядро Arch Linux", completed: true },
  { id: 2, name: "Налаштувати кольори Waybar", completed: false },
  { id: 3, name: "Зробити бекап дотфайлів", completed: false },
];

export default function App() {
  const [tasks, setTasks] = useState(initialTasks);

  const [text, newText] = useState("");

  function toggleTask(clickedId) {
    setTasks(
      tasks.map((task) =>
        task.id === clickedId ? { ...task, completed: !task.completed } : task,
      ),
    );
  }

  function deleteTask(clickedId) {
    setTasks(tasks.filter((task) => task.id !== clickedId));
  }

  return (
    <div className="app-container">
      <h1>Менеджер завдань</h1>
      <div className="task-list">
        {tasks.map((task) => (
          <div
            className={`task ${task.completed ? "done" : "pending"}`}
            key={task.id}
          >
            <p
              onClick={() => toggleTask(task.id)}
              style={{ cursor: "pointer", flexGrow: 1 }}
            >
              {task.name}
            </p>
            <button
              className="delete"
              onClick={(e) => {
                e.stopPropagation();
                deleteTask(task.id);
              }}
            >
              ❌
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
